mapper.select:
SELECT p.*, c.title as competition_title, u.real_name as student_name, u.student_id as student_id_str
FROM payment p
LEFT JOIN registration r ON p.registration_id = r.id
LEFT JOIN competition c ON r.competition_id = c.id
LEFT JOIN user u ON p.student_id = u.id

    
        AND p.registration_id = #{registrationId}
    
    
        AND p.student_id = #{studentId}
    
    
        AND p.status = #{status}
    

ORDER BY p.create_time DESC

